// Correct: POST to VibeTree proxy only. Never call OpenAI/Claude directly.
private let kApiBaseURL = "__VIBETREE_API_BASE_URL__"
private let kAppToken = "__VIBETREE_APP_TOKEN__"

func sendToProxy(messages: [[String: String]], systemPrompt: String, userId: String) async throws -> String {
  guard let url = URL(string: kApiBaseURL + "/api/proxy/ai") else { throw NSError(domain: "App", code: -1, userInfo: [NSLocalizedDescriptionKey: "Invalid URL"]) }
  var request = URLRequest(url: url)
  request.httpMethod = "POST"
  request.setValue("application/json", forHTTPHeaderField: "Content-Type")
  request.setValue(kAppToken, forHTTPHeaderField: "X-App-Token")
  let body: [String: Any] = ["messages": messages, "systemPrompt": systemPrompt, "userId": userId]
  request.httpBody = try JSONSerialization.data(withJSONObject: body)
  let (data, response) = try await URLSession.shared.data(for: request)
  guard let http = response as? HTTPURLResponse else { throw NSError(domain: "App", code: -1, userInfo: [NSLocalizedDescriptionKey: "Invalid response"]) }
  if http.statusCode == 401 { throw NSError(domain: "App", code: 401, userInfo: [NSLocalizedDescriptionKey: "Please sign in"]) }
  if http.statusCode == 402 { throw NSError(domain: "App", code: 402, userInfo: [NSLocalizedDescriptionKey: "Insufficient credits"]) }
  guard (200...299).contains(http.statusCode) else { throw NSError(domain: "App", code: http.statusCode, userInfo: [NSLocalizedDescriptionKey: "Request failed"]) }
  struct ProxyResponse: Decodable { let response: String? }
  if let decoded = try? JSONDecoder().decode(ProxyResponse.self, from: data), let text = decoded.response, !text.isEmpty { return text }
  return String(data: data, encoding: .utf8) ?? ""
}
